import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import includes from "lodash/includes";
import PropTypes from "prop-types";
import classNames from "classnames";
import { connect } from "react-redux";
import { InjectLocale } from "../../../../../decorators/locale";
import buildActions from "../../../store/actions";
import { isMobile, isPhone } from "../../../../../../common/constants/user-agent";
import { Classes } from "../../../../../../common/constants/classes";
import { sendScore } from "../../../../../utils/score";
import { Key } from "../../../../../../common/constants/keyboard";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import { DragNDrop } from "../../../../../decorators/dnd";
import { FeedbackSoundManager } from "../../../../../utils/sound";
import { trapTabKey } from "../../../../../utils/accessibility";
import { getBounds } from "../../../../../utils/bounds";
import DropZone, { dropZoneStyles } from "../../../../common/components/DropZone/DropZone";
import DragItem, { dragItemStyles } from "../../../../common/components/DragItem/DragItem";
import Controls from "../Controls/Controls";
import Background from "../Background/Background";

@connect(
  state => {
    return {
      ...state,
      activityId: state.id,
      activityType: state.type,
      activityName: state.name,
      finalResponse: "Completed!"
    };
  },
  buildActions
)
@InjectLocale("Activity")
@DragNDrop
class Activity extends PureComponent {
  static propTypes = {
    activityId: PropTypes.number.isRequired,
    activityType: PropTypes.string.isRequired,
    activityName: PropTypes.string.isRequired,
    background: PropTypes.string.isRequired,
    restart: PropTypes.func.isRequired,
    zones: PropTypes.arrayOf(PropTypes.object),
    items: PropTypes.arrayOf(PropTypes.object),
    showAnswers: PropTypes.bool.isRequired,
    showRestart: PropTypes.bool.isRequired,
    score: PropTypes.number.isRequired,
    activityAlign: PropTypes.object
  };

  state = {
    itemSize: {
      width: 0,
      height: 0
    },
    displayedScore: 0
  };

  labelWidth = 158;
  labelHeight = 43;
  circleRadius = 25;

  activeDropZoneSelector = `.${styles.container} .${dropZoneStyles.container}:not(.${
    dropZoneStyles.correct
  })`;
  remainingItemSelector = `.${styles.items} .${dragItemStyles.container}`;

  playerStyle = {
    ...this.props.activityAlign
  };

  constructor(...args) {
    super(...args);

    this.onResize = this.onResize.bind(this);
  }

  componentDidMount() {
    const { activityId, activityType } = this.props;
    const activityData = JSON.parse(sessionStorage.getItem(`${activityType}-${activityId}`));

    if (
      activityData &&
      activityData.hasOwnProperty("pointsEarned") &&
      activityData.hasOwnProperty("isRestart")
    ) {
      if (activityData.isRestart === false) {
        this.setState(
          {
            displayedScore: activityData.pointsEarned,
            complete: true
          },
          () => {
            this.completeActivity();
          }
        );
      }
    }

    window.addEventListener("resize", this.onResize);
    let event;

    if (typeof Event === "function") {
      event = new Event("resize");
    } else {
      event = document.createEvent("Event");
      event.initEvent("resize", true, true);
    }

    this.refs.itemsRef.style.maxHeight =
      this.refs.canvasRef.querySelector("svg").getBoundingClientRect().height + "px";

    window.dispatchEvent(event);
  }

  onResize() {
    const { zones, items, id } = this.props;
    const zoneType = isPhone() ? "circle" : "rect";
    const playerBounds = getBounds(this.playerNode);
    let itemBounds;

    this.zoneOffsets = [];

    zones.forEach(item => {
      const zoneShape = document.querySelector(`#labelling${id} #zone-${zoneType}-${item.labelId}`);

      if (zoneShape) {
        zoneShape.classList.remove(Classes.HIDDEN);
        itemBounds = getBounds(zoneShape);
        const center = {
          top: itemBounds.top + itemBounds.height / 2,
          left: itemBounds.left + itemBounds.width / 2
        };

        const labelWidth = isMobile ? this.circleRadius : this.labelWidth,
          labelHeight = isMobile ? this.circleRadius : this.labelHeight,
          top = center.top - playerBounds.top - labelHeight / 2,
          left = center.left - playerBounds.left - labelWidth / 2;

        this.zoneOffsets.push({
          top: top,
          left: left,
          right: left + labelWidth,
          bottom: top + labelHeight
        });
        zoneShape.classList.add(Classes.HIDDEN);
      }
    });

    items.forEach((item, index) => {
      const dragItem = this.dragItems[index];
      if (dragItem.correct) {
        if (!isMobile) {
          dragItem.setPosition(this.zoneOffsets[item.id].left, this.zoneOffsets[item.id].top);
        }
      }
    });
    this.forceUpdate();
  }

  handleStop = data => {
    const { zones } = this.props;
    const dragItemId = this.state.currentItemId;
    const dragItemIndex = this.state.currentItemIndex;
    const { inPlayerPos, initialPos } = data;
    let correctDrop = false;
    let dropZoneIndex;
    this.zoneOffsets.forEach((item, index) => {
      if (
        inPlayerPos.x > item.left &&
        inPlayerPos.x < item.right &&
        inPlayerPos.y > item.top &&
        inPlayerPos.y < item.bottom &&
        dragItemId === zones[index].id
      ) {
        correctDrop = true;
        dropZoneIndex = index;
      }
    });

    if (correctDrop) {
      this.handleCorrectDrop(dragItemIndex, dropZoneIndex);
    } else {
      this.handleIncorrectDrop(dragItemIndex, initialPos);
    }

    this.setState({
      transitionItemIndexes: this.state.transitionItemIndexes.concat(dragItemIndex),
      currentItemIndex: null,
      currentItemId: null,
      activeZoneIndex: null
    });
  };

  handleCorrectDrop = (dragItemIndex, dropZoneIndex) => {
    const { score, zones, items, activityId, activityType, playFeedbackSounds } = this.props;
    const correctZoneIndexes = this.state.correctZoneIndexes.concat(dropZoneIndex);

    // NOTE: This magic need for understand code below
    const correctCount = (() => {
      const l = items.filter((item, index) => {
        return this.dragItems[index].correct && !this.dragItems[index].mistakes;
      }).length;

      const m = this.dragItems[dragItemIndex].mistakes ? 0 : 1;

      return l + m;
    })();

    const displayedScore = parseFloat((score * (correctCount / items.length)).toFixed(1));
    let complete = this.state.complete;

    if (correctZoneIndexes.length === zones.length) {
      sendScore({
        id: activityId,
        type: activityType,
        pointsEarned: displayedScore,
        maxValue: score,
        isRestart: false
      });
      complete = true;
    }

    this.setState({
      correctZoneIndexes,
      displayedScore,
      complete
    });

    const dragItem = this.dragItems[dragItemIndex];

    dragItem.setPosition(this.zoneOffsets[dropZoneIndex].left, this.zoneOffsets[dropZoneIndex].top);
    dragItem.setCorrect(true);

    if (playFeedbackSounds) {
      FeedbackSoundManager.playCorrect();
    }
  };

  handleIncorrectDrop = (dragItemIndex, pos) => {
    const { playFeedbackSounds } = this.props;
    const dragItem = this.dragItems[dragItemIndex];
    if (pos) {
      dragItem.setPosition(pos.left, pos.top);
    }
    dragItem.setCorrect(false);

    if (playFeedbackSounds) {
      FeedbackSoundManager.playWrong();
    }
  };

  restart = () => {
    const { restart, activityId, activityType, score } = this.props;

    sendScore({
      id: activityId,
      type: activityType,
      pointsEarned: 0,
      maxValue: score,
      isRestart: true
    });

    this.setState({
      correctZoneIndexes: [],
      transitionItemIndexes: [],
      ariaText: this.locale.restart,
      displayedScore: 0,
      complete: false
    });

    restart();

    for (let i = 0; i < this.dragItems.length; i++) {
      this.dragItems[i].setState({
        correct: false,
        disabled: false,
        mistakes: 0,
        detached: false,
        left: 0,
        top: 0
      });
    }
  };

  completeActivity = e => {
    if (this.state.transitionItemIndexes.length === 0) {
      const { items, activityId, activityType, score, showAnswers } = this.props;
      const { correctZoneIndexes } = this.state;
      const incorrectIndexes = items
        .filter((item, index) => !this.dragItems[index].correct)
        .map((item, index) => index);

      if (e) {
        sendScore({
          id: activityId,
          type: activityType,
          pointsEarned: this.state.displayedScore,
          maxValue: score,
          isRestart: false
        });
      }

      this.setState(
        {
          transitionItemIndexes: incorrectIndexes,
          correctZoneIndexes: showAnswers
            ? this.props.zones.map((_, index) => index)
            : correctZoneIndexes,
          ariaText: this.locale.show_answers,
          complete: true
        },
        () => {
          items.forEach((item, index) => {
            const dragItem = this.dragItems[index];

            if (!dragItem.correct) {
              if (!isMobile && showAnswers) {
                dragItem.setDetached(true);
                dragItem.setPosition(this.zoneOffsets[item.id].left, this.zoneOffsets[item.id].top);
              }
              dragItem.setCorrect(true, true);
            }
          });
        }
      );
    }
  };

  onActivityKeyDown = e => {
    const { showRestart } = this.props;

    switch (e.keyCode) {
      case Key.R:
        if (e.altKey) {
          e.preventDefault();
          if (showRestart) {
            this.restart();
          }
        }
        break;
      case Key.S:
        if (e.altKey) {
          e.preventDefault();
          this.completeActivity();
        }
        break;
      default:
    }
  };

  onCanvasKeyDown = e => {
    if (e.keyCode === Key.TAB && !this.state.complete) {
      trapTabKey(e);
    }
  };

  get dragBlock() {
    const { items, id } = this.props;
    const { currentItemIndex, transitionItemIndexes, itemSize } = this.state;
    const labelingID = "labeling" + id;

    this._dragItems = [];

    return items.map((item, index) => {
      const active = index === currentItemIndex;
      const transition = includes(transitionItemIndexes, index);
      const disabled = () =>
        transitionItemIndexes.length !== 0 && !includes(transitionItemIndexes, index);
      const key = labelingID + "item" + item.id;

      return (
        <DragItem
          ref={ref => this._dragItems.push(ref)}
          key={key}
          index={index}
          notFocusable={this.state.notFocusable}
          active={active}
          transition={transition}
          disabled={disabled}
          value={item.value}
          parentSelector={"#labelling" + id}
          size={itemSize}
          onStart={this.handleStart}
          onStop={this.handleStop}
          onDrag={this.handleDrag}
          onKeyDown={this.onDragItemKeyDown}
          onFocus={this.onDragItemFocus}
          onTransitionEnd={this.onTransitionEnd}
        />
      );
    });
  }

  get dropBlock() {
    const { zones, items, id, showAnswers } = this.props;
    const { activeZoneIndex, correctZoneIndexes, notFocusable, itemSize, complete } = this.state;
    const notMatchedLabels = zones
      .filter(el => !includes(correctZoneIndexes, el.id))
      .map(el => el.value);
    const itemsToDisplay = items.filter(el => includes(notMatchedLabels, el.value));

    return zones.map((item, index) => {
      const activeZone = index === activeZoneIndex;
      const correctZone = includes(correctZoneIndexes, index) || (complete && showAnswers);
      return (
        <DropZone
          labelingID={id}
          showAnswers={showAnswers}
          key={index}
          index={index}
          items={itemsToDisplay}
          id={item.id}
          notFocusable={notFocusable}
          complete={complete}
          active={activeZone}
          correct={correctZone}
          size={itemSize}
          onCorrectSelect={this.handleCorrectDrop}
          onIncorrectSelect={this.handleIncorrectDrop}
          onKeyDown={this.onDropZoneKeyDown}
          {...this.zoneOffsets[index]}
          {...item}
        />
      );
    });
  }

  render() {
    const { score, studentInstruction, finalResponse, activityName, showRestart, id } = this.props;
    const { ariaText, displayedScore, complete } = this.state;

    return (
      <section tabIndex="0" className={styles.container} onKeyDown={this.onActivityKeyDown}>
        <AdaHelper ariaText={ariaText} />
        <ActivityHeader activityName={activityName} studentInstruction={studentInstruction} />

        <div
          role="application"
          style={this.playerStyle}
          ref={elem => (this.playerNode = elem)}
          className={styles.player}
          id={`labelling` + id}
        >
          <Controls
            displayedScore={displayedScore}
            totalScore={score}
            complete={complete}
            showRestart={showRestart}
            onButtonFocus={this.onButtonFocus}
            restart={this.restart}
            completeActivity={this.completeActivity}
          />
          <div className={styles.response}>{complete && <span>{finalResponse}</span>}</div>
          <div className={styles.body}>
            <div
              ref="itemsRef"
              className={classNames(styles.items, isMobile && styles["items-mobile"])}
            >
              {this.dragBlock}
            </div>

            <div ref="canvasRef" className={styles.canvas} onKeyDown={this.onCanvasKeyDown}>
              <Background background={this.props.background} />
              {this.dropBlock}
            </div>
          </div>
        </div>
      </section>
    );
  }
}

export default Activity;
