import styles from "./Background.module.scss";
import React, { Component } from "react";
import PropTypes from "prop-types";
import { isMSBrowser } from "../../../../../../common/constants/user-agent";

export default class Background extends Component {
  static propTypes = {
    background: PropTypes.string.isRequired
  };

  componentDidMount() {
    this.onResize();
    window.addEventListener("resize", this.onResize);
  }

  shouldComponentUpdate() {
    return false;
  }

  onResize = () => {
    if (isMSBrowser) {
      const svg = this.refs.root.querySelector("svg");
      const [x, y, width, height] = svg.getAttribute("viewBox").split(" "); // eslint-disable-line

      svg.setAttribute("height", (svg.parentNode.offsetWidth / width) * height);
    }
  };

  render() {
    return (
      <div
        ref="root"
        className={styles.container}
        dangerouslySetInnerHTML={{ __html: this.props.background }}
      />
    );
  }
}
