import cloneDeep from "lodash/cloneDeep";
import shuffle from "lodash/shuffle";

export default state => {
  let items = [];
  let zones = [];

  state.labels.forEach((item, index) => {
    items.push({
      id: index,
      value: item.value
    });
    zones.push(Object.assign({ id: index }, item));
  });

  items = shuffle(items);

  return {
    ...state,
    items,
    zones,
    initialItems: cloneDeep(items)
  };
};
