import { Howl } from "howler";
import correct from "../assets/audio/correct.mp3";
import wrong from "../assets/audio/wrong.mp3";

class SoundManager {
  constructor() {
    this.correct = new Howl({
      src: [correct]
    });

    this.wrong = new Howl({
      src: [wrong]
    });
  }

  playCorrect() {
    this.stop();
    if (this.correct.state() === "unloaded") {
      this.correct.on("load", () => {
        this.correct = new Howl({
          src: [correct]
        });
        this.correct.play();
      });
      this.correct.load();
    } else {
      this.correct.play();
    }
  }

  playWrong() {
    this.stop();
    if (this.wrong.state() === "unloaded") {
      this.wrong.on("load", () => {
        this.wrong = new Howl({
          src: [wrong]
        });
        this.wrong.play();
      });
      this.wrong.load();
    } else {
      this.wrong.play();
    }
  }

  stop() {
    if (this.correct.playing()) {
      this.correct.stop();
    }

    if (this.wrong.playing()) {
      this.wrong.stop();
    }
  }
}

export const FeedbackSoundManager = new SoundManager();
