import styles from "./ShortcutsButton.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { InjectLocale } from "../../../../decorators/locale";
import { Buttons } from "../../../../constants/buttons";
import { Animations } from "../../../../../common/constants/animations";
import { Classes } from "../../../../../common/constants/classes";
import { Key } from "../../../../../common/constants/keyboard";
import Button, { buttonStyles } from "../Button/Button";
import List, { listStyles } from "../List/List";

@InjectLocale("Shortcuts")
class ShortcutsButton extends PureComponent {
  static propTypes = {
    excludeItems: PropTypes.object,
    listPosition: PropTypes.string
  };

  static defaultProps = {
    excludeItems: null,
    listPosition: "bottom"
  };

  state = {
    listClass: Classes.HIDDEN,
    listExpanded: false
  };

  componentDidMount() {
    this.refs.container.addEventListener("focusout", this.onBlur);
  }

  onButtonClick = () => {
    this.state.listExpanded ? this.hide() : this.show();
  };

  onButtonKeyDown = e => {
    if (e.keyCode === Key.TAB && e.shiftKey) {
      this.hide();
    }
  };

  onBlur = e => {
    if (!this.refs.container.contains(e.relatedTarget)) {
      this.hide();
    }
  };

  show() {
    this.setState({
      listClass: Animations.FADE_IN,
      listExpanded: true
    });
  }

  hide() {
    this.setState({
      listClass: Classes.HIDDEN,
      listExpanded: false
    });
  }

  onListKeyDown = (index, e) => {
    if (e.keyCode === Key.TAB) {
      if (!e.shiftKey && index === this.listItems.length - 1) {
        this.hide();
      }
    }
  };

  get listItems() {
    const { excludeItems } = this.props;

    return excludeItems
      ? Object.values(this.locale).filter(item => !excludeItems[item.action])
      : Object.values(this.locale);
  }

  render() {
    const { listClass, listExpanded } = this.state;
    const { listPosition, className } = this.props;

    return (
      <div ref="container" className={classNames(styles.container, className)}>
        <Button
          id={Buttons.NAVIGATION}
          className={buttonStyles.navigation}
          onClick={this.onButtonClick}
          onKeyDown={this.onButtonKeyDown}
          hint={true}
          ariaExpanded={listExpanded}
        />
        <List
          items={this.listItems}
          className={classNames(listClass, listStyles[listPosition])}
          onKeyDown={this.onListKeyDown}
        />
      </div>
    );
  }
}

export default ShortcutsButton;
