import cloneDeep from "lodash/cloneDeep";
import types from "./types";

export default {
  [types.DISABLE_ITEM](state, action) {
    const items = [...state.items];

    items[action.index] = {
      ...items[action.index],
      disabled: true
    };

    return {
      ...state,
      items
    };
  },
  [types.RESTART](state) {
    return {
      ...state,
      items: cloneDeep(state.initialItems)
    };
  }
};
